import { useEffect, useRef, useState } from 'react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { Check } from 'lucide-react';
import { pricingConfig } from '../config';

gsap.registerPlugin(ScrollTrigger);

export function Pricing() {
  const sectionRef = useRef<HTMLElement>(null);
  const titleRef = useRef<HTMLHeadingElement>(null);
  const subtitleRef = useRef<HTMLParagraphElement>(null);
  const cardsRef = useRef<(HTMLDivElement | null)[]>([]);
  const [animatedPrices, setAnimatedPrices] = useState<number[]>([]);
  const triggersRef = useRef<ScrollTrigger[]>([]);

  if (!pricingConfig.title || pricingConfig.plans.length === 0) return null;

  const plans = pricingConfig.plans;

  useEffect(() => {
    setAnimatedPrices(new Array(plans.length).fill(0));

    const section = sectionRef.current;
    if (!section) return;

    const trigger = ScrollTrigger.create({
      trigger: section,
      start: 'top 80%',
      onEnter: () => {
        const tl = gsap.timeline();

        // Title fade up
        tl.fromTo(
          titleRef.current,
          { y: 40, opacity: 0 },
          { y: 0, opacity: 1, duration: 0.7, ease: 'expo.out' }
        );

        // Subtitle
        tl.fromTo(
          subtitleRef.current,
          { y: 20, opacity: 0 },
          { y: 0, opacity: 1, duration: 0.5, ease: 'power2.out' },
          '-=0.4'
        );

        // Cards 3D rotation entry
        cardsRef.current.forEach((card, i) => {
          if (card) {
            const rotateStart = i === 0 ? -45 : i === 2 ? 45 : 0;
            const translateX = i === 0 ? -100 : i === 2 ? 100 : 0;
            const translateY = i === 1 ? 80 : 0;
            const scaleStart = i === 1 ? 0.8 : 1;

            tl.fromTo(
              card,
              {
                rotateY: rotateStart,
                x: translateX,
                y: translateY,
                scale: scaleStart,
                opacity: 0,
              },
              {
                rotateY: 0,
                x: 0,
                y: 0,
                scale: 1,
                opacity: 1,
                duration: i === 1 ? 1.1 : 1,
                ease: i === 1 ? 'back.out(1.7)' : 'expo.out',
              },
              i === 1 ? '-=0.7' : `-=${0.8 - i * 0.1}`
            );

            // Red accent line for featured
            if (plans[i].featured) {
              const accentLine = card.querySelector('.accent-line');
              if (accentLine) {
                tl.fromTo(
                  accentLine,
                  { width: 0 },
                  { width: '100%', duration: 0.8, ease: 'expo.inOut' },
                  '-=0.5'
                );
              }
            }

            // Features stagger
            const features = card.querySelectorAll('.feature-item');
            tl.fromTo(
              features,
              { x: -10, opacity: 0 },
              {
                x: 0,
                opacity: 1,
                duration: 0.4,
                stagger: 0.05,
                ease: 'power2.out',
              },
              '-=0.6'
            );
          }
        });

        // Animate price counters
        plans.forEach((plan, i) => {
          const obj = { value: 0 };
          gsap.to(obj, {
            value: plan.price,
            duration: 1.2,
            delay: 0.5,
            ease: 'power2.out',
            onUpdate: () => {
              setAnimatedPrices((prev) => {
                const newPrices = [...prev];
                newPrices[i] = Math.round(obj.value);
                return newPrices;
              });
            },
          });
        });
      },
      once: true,
    });
    triggersRef.current.push(trigger);

    return () => {
      triggersRef.current.forEach((t) => t.kill());
      triggersRef.current = [];
    };
  }, []);

  const handleCardHover = (index: number, isEntering: boolean) => {
    const card = cardsRef.current[index];
    if (!card) return;

    if (isEntering) {
      gsap.to(card, {
        y: -10,
        z: 30,
        rotateY: 0,
        boxShadow: '0 30px 60px rgba(0,0,0,0.4)',
        duration: 0.4,
        ease: 'expo.out',
      });
    } else {
      gsap.to(card, {
        y: 0,
        z: 0,
        rotateY: 0,
        boxShadow: '0 10px 30px rgba(0,0,0,0.2)',
        duration: 0.4,
        ease: 'power2.out',
      });
    }
  };

  if (!pricingConfig.title || pricingConfig.plans.length === 0) return null;

  return (
    <section
      ref={sectionRef}
      id="pricing"
      className="relative py-20 md:py-32 px-6 md:px-8 lg:px-16 bg-black overflow-hidden"
    >
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="text-center mb-16">
          <h2
            ref={titleRef}
            className="text-h2 md:text-h1 lg:text-display-xl text-white font-medium mb-4"
          >
            {pricingConfig.title}
          </h2>
          <p ref={subtitleRef} className="text-body-lg text-white/60">
            {pricingConfig.subtitle}
          </p>
        </div>

        {/* Pricing cards */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 lg:gap-8 items-stretch">
          {plans.map((plan, index) => (
            <div
              key={plan.id}
              ref={(el) => {
                cardsRef.current[index] = el;
              }}
              className={`relative p-6 lg:p-12 rounded-2xl flex flex-col transition-all duration-500 hover-lift preserve-3d
                ${plan.featured
                  ? 'border border-gold/40 bg-gradient-to-br from-[#1a1814] to-black transform lg:scale-105 z-10'
                  : 'luxury-glass backdrop-blur-md opacity-90 hover:opacity-100'
                }
              `}
              style={{
                transformStyle: 'preserve-3d',
                willChange: 'transform, box-shadow',
              }}
              onMouseEnter={() => handleCardHover(index, true)}
              onMouseLeave={() => handleCardHover(index, false)}
            >
              {/* Featured accent line */}
              {plan.featured && (
                <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-gold-deep via-gold to-gold-deep opacity-80" />
              )}

              {/* Featured Badge */}
              {plan.featured && (
                <div className="absolute -top-4 left-1/2 -translate-x-1/2 px-4 py-1 bg-gold/10 border border-gold/30 rounded-full backdrop-blur-md">
                  <span className="text-body-sm font-medium shimmer-text uppercase tracking-widest">
                    Most Popular
                  </span>
                </div>
              )}

              {/* Plan name */}
              <h3
                className={`text-h5 mb-6 ${plan.featured ? 'text-gold' : 'text-white/80'
                  }`}
              >
                {plan.name}
              </h3>

              {/* Price */}
              <div className="mb-8">
                <span className="text-h4 lg:text-h3 font-medium tabular-nums">
                  ${(animatedPrices[index] || 0).toLocaleString()}.00
                </span>
                <span
                  className={`text-body ml-2 ${plan.featured ? 'text-black/60' : 'text-white/60'
                    }`}
                >
                  / {plan.unit}
                </span>
              </div>

              {/* Features */}
              <ul className="space-y-4 mb-10">
                {plan.features.map((feature, i) => (
                  <li
                    key={i}
                    className={`feature-item flex items-center gap-3 text-body ${plan.featured ? 'text-black/70' : 'text-white/70'
                      }`}
                  >
                    <Check
                      className={`w-5 h-5 flex-shrink-0 ${plan.featured ? 'text-highlight' : 'text-highlight'
                        }`}
                    />
                    {feature}
                  </li>
                ))}
              </ul>

              {/* CTA Button */}
              <button
                className={`w-full py-4 rounded-full font-medium transition-all duration-300 relative overflow-hidden group border
                  ${plan.featured
                    ? 'bg-gold text-black border-gold hover:bg-gold-light'
                    : 'bg-transparent text-white border-white/20 hover:border-gold hover:text-gold'
                  }
                `}
              >
                {pricingConfig.ctaButtonText}
              </button>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

import { useEffect, useRef, useState } from 'react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { servicesConfig } from '../config';

gsap.registerPlugin(ScrollTrigger);

export function Services() {
  const sectionRef = useRef<HTMLElement>(null);
  const titleRef = useRef<HTMLHeadingElement>(null);
  const subtitleRef = useRef<HTMLParagraphElement>(null);
  const itemsRef = useRef<(HTMLDivElement | null)[]>([]);
  const imageRef = useRef<HTMLDivElement>(null);
  const imagePreviewRef = useRef<HTMLDivElement>(null);
  const [activeIndex, setActiveIndex] = useState<number | null>(null);
  const [isTouchDevice, setIsTouchDevice] = useState(() => {
    if (typeof window !== 'undefined') {
      return window.matchMedia('(hover: none)').matches;
    }
    return false;
  });
  const mousePos = useRef({ x: 0, y: 0 });
  const triggersRef = useRef<ScrollTrigger[]>([]);

  useEffect(() => {
    if (!servicesConfig.title || servicesConfig.services.length === 0) return;

    const section = sectionRef.current;
    if (!section) return;

    // Entry animation
    const trigger = ScrollTrigger.create({
      trigger: section,
      start: 'top 80%',
      onEnter: () => {
        const tl = gsap.timeline();

        // Title slide in
        tl.fromTo(
          titleRef.current,
          { y: 60, opacity: 0, letterSpacing: '20px' },
          {
            y: 0,
            opacity: 1,
            letterSpacing: '0px',
            duration: 0.8,
            ease: 'expo.out',
          }
        );

        // Subtitle blur
        tl.fromTo(
          subtitleRef.current,
          { filter: 'blur(15px)', opacity: 0 },
          { filter: 'blur(0)', opacity: 1, duration: 0.6, ease: 'power2.out' },
          '-=0.4'
        );

        // Service items stagger
        itemsRef.current.forEach((item, i) => {
          if (item) {
            const line = item.querySelector('.service-line');
            const number = item.querySelector('.service-number');

            if (line) {
              tl.fromTo(
                line,
                { width: 0 },
                { width: '100%', duration: 1, ease: 'expo.inOut' },
                `-=${0.8 - i * 0.2}`
              );
            }

            if (number) {
              tl.fromTo(
                number,
                { scale: 0.5, opacity: 0 },
                { scale: 1, opacity: 1, duration: 0.8, ease: 'elastic.out(1, 0.5)' },
                `-=0.7`
              );
            }

            // Animate the whole item as fallback
            tl.fromTo(
              item,
              { y: 30, opacity: 0 },
              { y: 0, opacity: 1, duration: 0.6, ease: 'power2.out' },
              `-=${0.5 - i * 0.1}`
            );
          }
        });
      },
      once: true,
    });
    triggersRef.current.push(trigger);

    return () => {
      triggersRef.current.forEach((t) => t.kill());
      triggersRef.current = [];
    };
  }, []);

  if (!servicesConfig.title || servicesConfig.services.length === 0) return null;

  // Custom cursor follow for image preview
  const handleMouseMove = (e: React.MouseEvent<HTMLElement>) => {
    if (isTouchDevice) return;
    if (!imagePreviewRef.current) return;
    const section = sectionRef.current;
    if (!section || !imageRef.current) return;

    const rect = section.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    mousePos.current = { x, y };

    gsap.to(imageRef.current, {
      x: x - 150,
      y: y - 200,
      duration: 0.15,
      ease: 'power2.out',
    });
  };

  const handleItemEnter = (index: number) => {
    if (isTouchDevice) return;
    setActiveIndex(index);
    if (imageRef.current) {
      gsap.to(imageRef.current, {
        opacity: 1,
        scale: 1,
        duration: 0.6,
        ease: 'expo.out',
      });
    }
  };

  const handleItemLeave = () => {
    setActiveIndex(null);
    if (imageRef.current) {
      gsap.to(imageRef.current, {
        opacity: 0,
        scale: 0.9,
        duration: 0.4,
        ease: 'power2.out',
      });
    }
  };

  const services = servicesConfig.services;

  return (
    <section
      ref={sectionRef}
      id="services"
      className="relative py-20 md:py-32 px-6 md:px-8 lg:px-16 bg-black overflow-hidden"
      onMouseMove={handleMouseMove}
    >
      {/* Floating image preview */}
      <div
        ref={imagePreviewRef}
        className="preview-container fixed top-0 left-0 w-[400px] aspect-[4/5] pointer-events-none z-50 overflow-hidden rounded-sm border border-gold/30 gold-border-glow shadow-2xl"
        style={{ opacity: 0, transform: 'scale(0.8) translate(-50%, -50%)', display: 'none' }}
      >
        {activeIndex !== null && (
          <img
            src={services[activeIndex].image}
            alt={services[activeIndex].title}
            className="w-full h-full object-cover"
          />
        )}
      </div>

      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-20">
          <h2
            ref={titleRef}
            className="text-h2 md:text-h1 lg:text-display-xl text-white font-medium mb-6"
          >
            {servicesConfig.title}
          </h2>
          <p
            ref={subtitleRef}
            className="text-body-lg text-white/60 max-w-2xl"
          >
            {servicesConfig.subtitle}
          </p>
        </div>

        {/* Services list */}
        <div className="space-y-0">
          {servicesConfig.services.map((service, index) => (
            <div
              key={index}
              ref={(el) => { itemsRef.current[index] = el; }} // Keep ref for potential future animations
              className="service-item group relative py-12 border-b border-gold/20 flex flex-col md:flex-row md:items-center justify-between cursor-pointer"
              onMouseEnter={() => handleItemEnter(index)}
              onMouseLeave={handleItemLeave}
            >
              {/* Service number & title */}
              <div className="flex items-center gap-8 md:gap-16 mb-6 md:mb-0 z-10">
                <span className="text-body text-gold/50 font-mono group-hover:text-gold group-hover:text-shadow-glow transition-all duration-300">
                  {String(index + 1).padStart(2, '0')}.
                </span>
                <h3
                  className={`text-h4 md:text-h3 lg:text-h2 text-white font-normal transition-all duration-400 ${activeIndex !== null && activeIndex !== index
                    ? 'opacity-30'
                    : 'opacity-100'
                    } ${activeIndex === index
                      ? 'text-shadow-glow'
                      : ''
                    }`}
                  style={{
                    textShadow:
                      activeIndex === index
                        ? '0 0 30px rgba(201,165,90,0.5)'
                        : 'none',
                  }}
                >
                  {service.title}
                </h3>
              </div>

              {/* Description */}
              <p
                className={`mt-4 lg:mt-0 text-body-sm md:text-body text-white/60 lg:text-white/40 lg:max-w-xs lg:text-right transition-opacity duration-300 ${activeIndex !== null && activeIndex !== index
                  ? 'lg:opacity-30'
                  : 'opacity-100'
                  }`}
              >
                {service.description}
              </p>
            </div>
          ))}
        </div>
      </div >
    </section >
  );
}

